import type { SVGProps } from "react";

type IconProps = {
  size?: number;
  stroke?: string;
  fill?: string;
  sw?: number;
} & Omit<SVGProps<SVGSVGElement>, "stroke" | "fill">;

function Icon({
  size = 22,
  stroke = "currentColor",
  fill = "none",
  sw = 1.6,
  children,
  ...rest
}: IconProps & { children: React.ReactNode }) {
  return (
    <svg
      width={size}
      height={size}
      viewBox="0 0 24 24"
      fill={fill}
      stroke={stroke}
      strokeWidth={sw}
      strokeLinecap="round"
      strokeLinejoin="round"
      aria-hidden="true"
      {...rest}
    >
      {children}
    </svg>
  );
}

export function DropIcon({
  size = 22,
  fill = "currentColor",
}: {
  size?: number;
  fill?: string;
}) {
  return (
    <svg
      width={size}
      height={size}
      viewBox="0 0 24 24"
      fill={fill}
      aria-hidden="true"
    >
      <path d="M12 3 C 12 3, 5 11, 5 15.5 A 7 7 0 0 0 19 15.5 C 19 11, 12 3, 12 3 Z" />
    </svg>
  );
}

